     {
         internal IDictionary<ResourceType, string> ResourceApiVersionOverrides { get; } = new Dictionary<ResourceType, string>();

         /// <summary>
         /// Gets or sets Azure cloud environment.
         /// </summary>
         public ArmEnvironment? Environment { get; set; }

